// WriteGeneratedFiles formats and writes generated files, skipping unchanged files.
func WriteGeneratedFiles(files []GeneratedFile) ([]WriteResult, []Diagnostic) {
	results := make([]WriteResult, 0, len(files))
	diagnostics := make([]Diagnostic, 0)

	for _, file := range files {
		formatted, diagnostic, ok := formatGeneratedFile(file)
		if !ok {
			diagnostics = append(diagnostics, diagnostic)
			continue
		}

		existing, err := os.ReadFile(file.Path)
		if err == nil && bytes.Equal(existing, formatted) {
			results = append(results, WriteResult{Path: file.Path})
			continue
		}
		if err != nil && !os.IsNotExist(err) {
			diagnostics = append(diagnostics, writeFailureDiagnostic(file.Path, err))
			continue
		}

		if err := os.MkdirAll(filepath.Dir(file.Path), 0o755); err != nil {
			diagnostics = append(diagnostics, writeFailureDiagnostic(file.Path, err))
			continue
		}
		if err := os.WriteFile(file.Path, formatted, 0o644); err != nil {
			diagnostics = append(diagnostics, writeFailureDiagnostic(file.Path, err))
			continue
		}
		results = append(results, WriteResult{Path: file.Path, Written: true})
	}

	sortDiagnostics(diagnostics)
	return results, diagnostics
}

func generatePackageMetadata(controllers []Controller) ([]byte, error) {
	if len(controllers) == 0 {
		return nil, nil
	}

	var buffer bytes.Buffer
	pkg := controllers[0].Package
	buffer.WriteString(generatedHeader)
	buffer.WriteString("\npackage ")
	buffer.WriteString(pkg.Name)
	buffer.WriteString("\n\n")
	writeGeneratedImports(&buffer, controllers)
	buffer.WriteString("\n")

	for index, controller := range controllers {
		if index > 0 {
			buffer.WriteString("\n")
		}
		writeControllerMetadata(&buffer, controller)
	}

	formatted, err := format.Source(buffer.Bytes())
	if err != nil {
		return nil, fmt.Errorf("format generated metadata for package %q: %w", pkg.ImportPath, err)
	}
	return formatted, nil
}

func writeGeneratedImports(buffer *bytes.Buffer, controllers []Controller) {
	imports := generatedImports(controllers)
	if len(imports) == 1 {
		buffer.WriteString("import \"github.com/r6m/gest\"\n\n")
		return
	}

	buffer.WriteString("import (\n")
	buffer.WriteString("\t\"github.com/r6m/gest\"\n")
	for _, imported := range imports {
		if imported.ImportPath == "github.com/r6m/gest" {
			continue
		}
		buffer.WriteString("\t")
		if imported.Alias != defaultImportAlias(imported.ImportPath) {
			buffer.WriteString(imported.Alias)
			buffer.WriteString(" ")
		}
		buffer.WriteString(strconv.Quote(imported.ImportPath))
		buffer.WriteString("\n")
	}
	buffer.WriteString(")\n\n")
}

