func writeGatewayMetadata(buffer *bytes.Buffer, gateway Gateway) {
	buffer.WriteString("func (g *")
	buffer.WriteString(gateway.TypeName)
	buffer.WriteString(") GestGateway() websocket.GatewayDefinition {\n")
	buffer.WriteString("\treturn websocket.GatewayDefinition{\n")
	buffer.WriteString("\t\tName: ")
	buffer.WriteString(strconv.Quote(gateway.TypeName))
	buffer.WriteString(",\n")
	buffer.WriteString("\t\tPath: ")
	buffer.WriteString(strconv.Quote(gateway.Path))
	buffer.WriteString(",\n")
	buffer.WriteString("\t\tSubscriptions: []websocket.SubscriptionDefinition{\n")
	for _, subscription := range gateway.Subscriptions {
		buffer.WriteString("\t\t\t{\n")
		buffer.WriteString("\t\t\t\tEvent: ")
		buffer.WriteString(strconv.Quote(subscription.Event))
		buffer.WriteString(",\n")
		buffer.WriteString("\t\t\t\tHandle: websocket.Handle[")
		buffer.WriteString(subscription.MessageType)
		buffer.WriteString("](g.")
		buffer.WriteString(subscription.HandlerName)
		buffer.WriteString("),\n")
		buffer.WriteString("\t\t\t},\n")
	}
	buffer.WriteString("\t\t},\n")
	buffer.WriteString("\t}\n")
	buffer.WriteString("}\n")
}

type generatedImport struct {
	Alias      string
	ImportPath string
}

func generatedImports(controllers []Controller) []generatedImport {
	byAlias := map[string]generatedImport{
		"gest": {Alias: "gest", ImportPath: "github.com/r6m/gest"},
	}
	for _, controller := range controllers {
		for _, guard := range controller.Guards {
			byAlias[guard.Alias] = generatedImport{Alias: guard.Alias, ImportPath: guard.ImportPath}
		}
		for _, route := range controller.Routes {
			for _, guard := range route.Guards {
				byAlias[guard.Alias] = generatedImport{Alias: guard.Alias, ImportPath: guard.ImportPath}
			}
		}
	}

	imports := make([]generatedImport, 0, len(byAlias))
	for _, imported := range byAlias {
		imports = append(imports, imported)
	}
	slices.SortFunc(imports, func(a generatedImport, b generatedImport) int {
		if a.ImportPath < b.ImportPath {
			return -1
		}
		if a.ImportPath > b.ImportPath {
			return 1
		}
		return strings.Compare(a.Alias, b.Alias)
	})
	return imports
}

func formatGeneratedFile(file GeneratedFile) ([]byte, Diagnostic, bool) {
	formatted, err := format.Source(file.Content)
	if err != nil {
		return nil, Diagnostic{
			Severity: SeverityError,
			Code:     DiagnosticFormatFailure,
			Message:  "format generated source: " + err.Error(),
			Hint:     "check generator output for invalid Go syntax",
			File:     file.Path,
		}, false
	}
	return formatted, Diagnostic{}, true
}

func writeFailureDiagnostic(path string, err error) Diagnostic {
	return Diagnostic{
		Severity: SeverityError,
		Code:     DiagnosticWriteFailure,
		Message:  "write generated file: " + err.Error(),
		Hint:     "check that the output path is writable and not occupied by a directory",
		File:     path,
	}
}

func writeControllerMetadata(buffer *bytes.Buffer, controller Controller) {
	buffer.WriteString("func (c *")
	buffer.WriteString(controller.TypeName)
	buffer.WriteString(") GestController() gest.ControllerDefinition {\n")
	buffer.WriteString("\treturn gest.ControllerDefinition{\n")
	buffer.WriteString("\t\tName: ")
	buffer.WriteString(strconv.Quote(controller.TypeName))
	buffer.WriteString(",\n")
	buffer.WriteString("\t\tBasePath: ")
	buffer.WriteString(strconv.Quote(controller.BasePath))
	buffer.WriteString(",\n")
	if controller.Tag != "" {
		buffer.WriteString("\t\tTag: ")
		buffer.WriteString(strconv.Quote(controller.Tag))
		buffer.WriteString(",\n")
	}
	if controller.Hidden {
		buffer.WriteString("\t\tHidden: true,\n")
	}
	buffer.WriteString("\t\tRoutes: []gest.RouteDefinition{\n")
	for _, route := range controller.Routes {
		writeRouteMetadata(buffer, controller, route)
	}
	buffer.WriteString("\t\t},\n")
	buffer.WriteString("\t}\n")
	buffer.WriteString("}\n")
}

func writeRouteMetadata(buffer *bytes.Buffer, controller Controller, route Route) {
	buffer.WriteString("\t\t\t{\n")
	buffer.WriteString("\t\t\t\tName: ")
	buffer.WriteString(strconv.Quote(route.HandlerName))
	buffer.WriteString(",\n")
	buffer.WriteString("\t\t\t\tMethod: ")
	buffer.WriteString(strconv.Quote(route.Method))
	buffer.WriteString(",\n")
	buffer.WriteString("\t\t\t\tPath: ")
	buffer.WriteString(strconv.Quote(route.Path))
	buffer.WriteString(",\n")
	writeHandlerMetadata(buffer, route)
	writeTypeMetadata(buffer, "Request", route.RequestType)
	writeTypeMetadata(buffer, "Response", route.ResponseType)
	writeStatusesMetadata(buffer, route.Statuses)
	writeRouteComponentMetadata(buffer, appendGuardReferences(controller.Guards, route.Guards))
	writeRouteDescriptionMetadata(buffer, route)
	buffer.WriteString("\t\t\t},\n")
}

func writeHandlerMetadata(buffer *bytes.Buffer, route Route) {
	buffer.WriteString("\t\t\t\tHandler: gest.")
	buffer.WriteString(handlerAdapter(route))
	buffer.WriteString("(c.")
	buffer.WriteString(route.HandlerName)
	if status, ok := successStatus(route.Statuses); ok {
		buffer.WriteString(", gest.Status(")
		buffer.WriteString(strconv.Itoa(status))
		buffer.WriteString(")")
	}
	buffer.WriteString("),\n")
}

func handlerAdapter(route Route) string {
	switch {
	case route.RequestType != "" && route.ResponseType != "":
		return "HandleRequestResponse"
	case route.RequestType != "":
		return "HandleRequest"
	case route.ResponseType != "":
		return "HandleResponse"
	default:
		return "HandleContext"
	}
}

func successStatus(statuses []int) (int, bool) {
	for _, status := range statuses {
		if status >= 200 && status < 300 {
			return status, true
		}
	}

	return 0, false
}

func writeTypeMetadata(buffer *bytes.Buffer, field string, typeName string) {
	if typeName == "" {
		return
	}
	buffer.WriteString("\t\t\t\t")
	buffer.WriteString(field)
	buffer.WriteString(": (*")
	buffer.WriteString(typeName)
	buffer.WriteString(")(nil),\n")
}

func writeStatusesMetadata(buffer *bytes.Buffer, statuses []int) {
	if len(statuses) == 0 {
		return
	}
	buffer.WriteString("\t\t\t\tStatuses: []int{")
	for index, status := range statuses {
		if index > 0 {
			buffer.WriteString(", ")
		}
		buffer.WriteString(strconv.Itoa(status))
	}
	buffer.WriteString("},\n")
}

func writeRouteComponentMetadata(buffer *bytes.Buffer, components []GuardReference) {
	if len(components) == 0 {
		return
	}
	buffer.WriteString("\t\t\t\tComponents: []gest.RouteComponentFactory{\n")
	for _, component := range components {
		componentType := component.Alias + "." + component.Symbol
		buffer.WriteString("\t\t\t\t\tgest.ResolveRouteComponent[*")
		buffer.WriteString(componentType)
		buffer.WriteString("](),\n")
	}
	buffer.WriteString("\t\t\t\t},\n")
}

func appendGuardReferences(controllerGuards []GuardReference, routeGuards []GuardReference) []GuardReference {
	if len(controllerGuards) == 0 {
		return routeGuards
	}
	guards := make([]GuardReference, 0, len(controllerGuards)+len(routeGuards))
	guards = append(guards, controllerGuards...)
	guards = append(guards, routeGuards...)
	return guards
}

func writeRouteDescriptionMetadata(buffer *bytes.Buffer, route Route) {
	if route.Summary == "" && route.Description == "" && !route.Hidden {
		return
	}
	buffer.WriteString("\t\t\t\tMetadata: gest.RouteMetadata{\n")
	if route.Hidden {
		buffer.WriteString("\t\t\t\t\tHidden: true,\n")
	}
	if route.Summary != "" {
		buffer.WriteString("\t\t\t\t\tSummary: ")
		buffer.WriteString(strconv.Quote(route.Summary))
		buffer.WriteString(",\n")
	}
	if route.Description != "" {
		buffer.WriteString("\t\t\t\t\tDescription: ")
		buffer.WriteString(strconv.Quote(route.Description))
		buffer.WriteString(",\n")
	}
	buffer.WriteString("\t\t\t\t},\n")
}
